      button.addEventListener('click',()=>{ const next=button.getAttribute('aria-expanded')!=='true'; if(next&&!allowMultiple) controls.forEach((other)=>{ if(other!==record) setOpen(other,false); }); setOpen(record,next); });
      wrap.appendChild(button); wrap.appendChild(panel); section.appendChild(wrap);
